#!/usr/bin/env python3

import os
import sys
import json
import hashlib
import subprocess
import argparse
from pathlib import Path
from typing import List, Dict, Optional, Set
from datetime import datetime
import re


class DependencyManager:
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root).resolve()
        self.requirements_file = self.project_root / "requirements.txt"
        self.requirements_dev_file = self.project_root / "requirements-dev.txt"
        self.requirements_lock_file = self.project_root / "requirements.lock"
        self.pyproject_file = self.project_root / "pyproject.toml"
        self.poetry_lock_file = self.project_root / "poetry.lock"
        self.dependency_audit_log = self.project_root / "dependency-audit.log"
        
    def detect_dependency_manager(self) -> str:
        if self.pyproject_file.exists():
            with open(self.pyproject_file, 'r') as f:
                content = f.read()
                if '[tool.poetry]' in content:
                    return 'poetry'
                elif '[project]' in content:
                    return 'pip'
        if self.requirements_file.exists():
            return 'pip'
        return 'unknown'
    
    def generate_requirements_with_hashes(self, input_file: Path, output_file: Path):
        print(f"Generating locked requirements with hashes from {input_file}...")
        
        if not input_file.exists():
            print(f"Error: {input_file} not found")
            return False
        
        try:
            result = subprocess.run(
                [sys.executable, "-m", "pip", "install", "--dry-run", 
                 "--report", "-", "-r", str(input_file)],
                capture_output=True,
                text=True,
                check=True
            )
            
            report = json.loads(result.stdout)
            
            with open(output_file, 'w') as f:
                f.write(f"# Generated on {datetime.now().isoformat()}\n")
                f.write(f"# Source: {input_file.name}\n")
                f.write("# This file is auto-generated. Do not edit manually.\n\n")
                
                for package in report.get('install', []):
                    metadata = package.get('metadata', {})
                    name = metadata.get('name', '')
                    version = metadata.get('version', '')
                    
                    if name and version:
                        download_info = package.get('download_info', {})
                        url = download_info.get('url', '')
                        
                        f.write(f"{name}=={version} \\\n")
                        
                        if url:
                            hash_value = self._get_package_hash(name, version)
                            if hash_value:
                                f.write(f"    --hash=sha256:{hash_value}\n")
                        else:
                            f.write("\n")
            
            print(f"Successfully generated {output_file}")
            return True
            
        except subprocess.CalledProcessError as e:
            print(f"Error generating requirements: {e.stderr}")
            return False
        except json.JSONDecodeError as e:
            print(f"Error parsing pip report: {e}")
            return False
    
    def _get_package_hash(self, package_name: str, version: str) -> Optional[str]:
        try:
            result = subprocess.run(
                [sys.executable, "-m", "pip", "hash", f"{package_name}=={version}"],
                capture_output=True,
                text=True,
                timeout=30
            )
            
            if result.returncode == 0:
                match = re.search(r'sha256:([a-f0-9]{64})', result.stdout)
                if match:
                    return match.group(1)
            
            result = subprocess.run(
                [sys.executable, "-m", "pip", "download", "--no-deps", 
                 f"{package_name}=={version}", "--dest", "/tmp"],
                capture_output=True,
                text=True,
                timeout=60
            )
            
            if result.returncode == 0:
                for line in result.stdout.split('\n'):
                    if 'Saved' in line or 'File was already downloaded' in line:
                        file_match = re.search(r'/tmp/([^\s]+)', line)
                        if file_match:
                            file_path = Path('/tmp') / file_match.group(1)
                            if file_path.exists():
                                hash_val = self._calculate_file_hash(file_path)
                                file_path.unlink()
                                return hash_val
            
        except (subprocess.TimeoutExpired, Exception) as e:
            print(f"Warning: Could not get hash for {package_name}=={version}: {e}")
        
        return None
    
    def _calculate_file_hash(self, file_path: Path) -> str:
        sha256_hash = hashlib.sha256()
        with open(file_path, "rb") as f:
            for byte_block in iter(lambda: f.read(4096), b""):
                sha256_hash.update(byte_block)
        return sha256_hash.hexdigest()
    
    def freeze_dependencies(self, output_file: Optional[Path] = None):
        if output_file is None:
            output_file = self.requirements_lock_file
        
        print("Freezing current environment dependencies...")
        
        try:
            result = subprocess.run(
                [sys.executable, "-m", "pip", "freeze"],
                capture_output=True,
                text=True,
                check=True
            )
            
            with open(output_file, 'w') as f:
                f.write(f"# Frozen on {datetime.now().isoformat()}\n")
                f.write("# This file contains exact versions of all installed packages\n\n")
                f.write(result.stdout)
            
            print(f"Dependencies frozen to {output_file}")
            return True
            
        except subprocess.CalledProcessError as e:
            print(f"Error freezing dependencies: {e.stderr}")
            return False
    
    def update_dependency(self, package_name: str, version: Optional[str] = None):
        print(f"Updating {package_name}...")
        
        self._log_audit(f"UPDATE: {package_name} to version {version or 'latest'}")
        
        try:
            if version:
                cmd = [sys.executable, "-m", "pip", "install", f"{package_name}=={version}"]
            else:
                cmd = [sys.executable, "-m", "pip", "install", "--upgrade", package_name]
            
            result = subprocess.run(cmd, capture_output=True, text=True, check=True)
            print(result.stdout)
            
            self.freeze_dependencies()
            return True
            
        except subprocess.CalledProcessError as e:
            print(f"Error updating {package_name}: {e.stderr}")
            return False
    
    def check_outdated_dependencies(self) -> List[Dict[str, str]]:
        print("Checking for outdated dependencies...")
        
        try:
            result = subprocess.run(
                [sys.executable, "-m", "pip", "list", "--outdated", "--format=json"],
                capture_output=True,
                text=True,
                check=True
            )
            
            outdated = json.loads(result.stdout)
            
            if outdated:
                print("\nOutdated packages:")
                print(f"{'Package':<30} {'Current':<15} {'Latest':<15} {'Type':<10}")
                print("-" * 70)
                for pkg in outdated:
                    print(f"{pkg['name']:<30} {pkg['version']:<15} {pkg['latest_version']:<15} {pkg.get('latest_filetype', 'N/A'):<10}")
            else:
                print("All packages are up to date!")
            
            return outdated
            
        except subprocess.CalledProcessError as e:
            print(f"Error checking outdated packages: {e.stderr}")
            return []
        except json.JSONDecodeError as e:
            print(f"Error parsing outdated packages: {e}")
            return []
    
    def verify_hashes(self, requirements_file: Path) -> bool:
        print(f"Verifying hashes in {requirements_file}...")
        
        if not requirements_file.exists():
            print(f"Error: {requirements_file} not found")
            return False
        
        try:
            result = subprocess.run(
                [sys.executable, "-m", "pip", "install", "--dry-run", 
                 "--require-hashes", "-r", str(requirements_file)],
                capture_output=True,
                text=True
            )
            
            if result.returncode == 0:
                print("All hashes verified successfully!")
                return True
            else:
                print(f"Hash verification failed:\n{result.stderr}")
                return False
                
        except subprocess.CalledProcessError as e:
            print(f"Error verifying hashes: {e.stderr}")
            return False
    
    def sync_dependencies(self, requirements_file: Path):
        print(f"Syncing dependencies from {requirements_file}...")
        
        if not requirements_file.exists():
            print(f"Error: {requirements_file} not found")
            return False
        
        self._log_audit(f"SYNC: Installing from {requirements_file}")
        
        try:
            cmd = [sys.executable, "-m", "pip", "install", "-r", str(requirements_file)]
            
            with open(requirements_file, 'r') as f:
                if '--hash=' in f.read():
                    cmd.append('--require-hashes')
            
            result = subprocess.run(cmd, capture_output=True, text=True, check=True)
            print(result.stdout)
            print(f"Successfully synced dependencies from {requirements_file}")
            return True
            
        except subprocess.CalledProcessError as e:
            print(f"Error syncing dependencies: {e.stderr}")
            return False
    
    def poetry_lock(self):
        print("Locking Poetry dependencies...")
        
        if not self.pyproject_file.exists():
            print("Error: pyproject.toml not found")
            return False
        
        self._log_audit("POETRY: Locking dependencies")
        
        try:
            result = subprocess.run(
                ["poetry", "lock"],
                capture_output=True,
                text=True,
                check=True,
                cwd=self.project_root
            )
            print(result.stdout)
            print(f"Poetry lock file updated: {self.poetry_lock_file}")
            return True
            
        except subprocess.CalledProcessError as e:
            print(f"Error locking Poetry dependencies: {e.stderr}")
            return False
        except FileNotFoundError:
            print("Error: Poetry not found. Please install Poetry first.")
            return False
    
    def poetry_update(self, package_name: Optional[str] = None):
        print(f"Updating Poetry dependencies{' for ' + package_name if package_name else ''}...")
        
        self._log_audit(f"POETRY UPDATE: {package_name or 'all packages'}")
        
        try:
            cmd = ["poetry", "update"]
            if package_name:
                cmd.append(package_name)
            
            result = subprocess.run(
                cmd,
                capture_output=True,
                text=True,
                check=True,
                cwd=self.project_root
            )
            print(result.stdout)
            return True
            
        except subprocess.CalledProcessError as e:
            print(f"Error updating Poetry dependencies: {e.stderr}")
            return False
        except FileNotFoundError:
            print("Error: Poetry not found. Please install Poetry first.")
            return False
    
    def poetry_export(self, output_file: Optional[Path] = None, with_hashes: bool = True):
        if output_file is None:
            output_file = self.requirements_lock_file
        
        print(f"Exporting Poetry dependencies to {output_file}...")
        
        try:
            cmd = ["poetry", "export", "-f", "requirements.txt", "-o", str(output_file)]
            if with_hashes:
                cmd.append("--with-hashes")
            
            result = subprocess.run(
                cmd,
                capture_output=True,
                text=True,
                check=True,
                cwd=self.project_root
            )
            print(f"Successfully exported to {output_file}")
            return True
            
        except subprocess.CalledProcessError as e:
            print(f"Error exporting Poetry dependencies: {e.stderr}")
            return False
        except FileNotFoundError:
            print("Error: Poetry not found. Please install Poetry first.")
            return False
    
    def check_security_vulnerabilities(self):
        print("Checking for security vulnerabilities...")
        
        try:
            result = subprocess.run(
                [sys.executable, "-m", "pip", "install", "safety"],
                capture_output=True,
                text=True
            )
            
            result = subprocess.run(
                [sys.executable, "-m", "safety", "check", "--json"],
                capture_output=True,
                text=True
            )
            
            if result.returncode == 0:
                vulnerabilities = json.loads(result.stdout)
                if vulnerabilities:
                    print("\nSecurity vulnerabilities found:")
                    for vuln in vulnerabilities:
                        print(f"\n{vuln.get('package', 'Unknown')} {vuln.get('installed_version', '')}")
                        print(f"  Vulnerability: {vuln.get('vulnerability', 'N/A')}")
                        print(f"  Affected versions: {vuln.get('affected_versions', 'N/A')}")
                        print(f"  Fixed in: {vuln.get('fixed_in', 'N/A')}")
                else:
                    print("No known security vulnerabilities found!")
            else:
                print("Could not check for vulnerabilities")
            
        except (subprocess.CalledProcessError, json.JSONDecodeError, FileNotFoundError) as e:
            print(f"Error checking vulnerabilities: {e}")
    
    def compare_lock_files(self, file1: Path, file2: Path):
        print(f"Comparing {file1} and {file2}...")
        
        if not file1.exists() or not file2.exists():
            print("Error: One or both files not found")
            return
        
        deps1 = self._parse_requirements(file1)
        deps2 = self._parse_requirements(file2)
        
        added = set(deps2.keys()) - set(deps1.keys())
        removed = set(deps1.keys()) - set(deps2.keys())
        common = set(deps1.keys()) & set(deps2.keys())
        
        changed = {pkg for pkg in common if deps1[pkg] != deps2[pkg]}
        
        if added:
            print(f"\nAdded packages ({len(added)}):")
            for pkg in sorted(added):
                print(f"  + {pkg}=={deps2[pkg]}")
        
        if removed:
            print(f"\nRemoved packages ({len(removed)}):")
            for pkg in sorted(removed):
                print(f"  - {pkg}=={deps1[pkg]}")
        
        if changed:
            print(f"\nChanged packages ({len(changed)}):")
            for pkg in sorted(changed):
                print(f"  ~ {pkg}: {deps1[pkg]} -> {deps2[pkg]}")
        
        if not (added or removed or changed):
            print("\nNo differences found!")
    
    def _parse_requirements(self, file_path: Path) -> Dict[str, str]:
        deps = {}
        with open(file_path, 'r') as f:
            for line in f:
                line = line.strip()
                if line and not line.startswith('#') and not line.startswith('--'):
                    match = re.match(r'([a-zA-Z0-9_-]+)==([0-9.]+)', line)
                    if match:
                        deps[match.group(1)] = match.group(2)
        return deps
    
    def _log_audit(self, message: str):
        timestamp = datetime.now().isoformat()
        with open(self.dependency_audit_log, 'a') as f:
            f.write(f"[{timestamp}] {message}\n")
    
    def generate_dependency_report(self, output_file: Optional[Path] = None):
        if output_file is None:
            output_file = self.project_root / "dependency-report.txt"
        
        print(f"Generating dependency report to {output_file}...")
        
        try:
            result = subprocess.run(
                [sys.executable, "-m", "pip", "list", "--format=json"],
                capture_output=True,
                text=True,
                check=True
            )
            
            packages = json.loads(result.stdout)
            
            with open(output_file, 'w') as f:
                f.write(f"Dependency Report - Generated on {datetime.now().isoformat()}\n")
                f.write("=" * 80 + "\n\n")
                f.write(f"Total packages: {len(packages)}\n\n")
                
                f.write(f"{'Package':<40} {'Version':<20}\n")
                f.write("-" * 60 + "\n")
                
                for pkg in sorted(packages, key=lambda x: x['name']):
                    f.write(f"{pkg['name']:<40} {pkg['version']:<20}\n")
            
            print(f"Report generated: {output_file}")
            return True
            
        except (subprocess.CalledProcessError, json.JSONDecodeError) as e:
            print(f"Error generating report: {e}")
            return False


def main():
    parser = argparse.ArgumentParser(
        description="Python Dependency Management Tool",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  # Generate locked requirements with hashes
  %(prog)s lock --input requirements.txt --output requirements.lock
  
  # Freeze current environment
  %(prog)s freeze
  
  # Check for outdated packages
  %(prog)s outdated
  
  # Update a specific package
  %(prog)s update requests --version 2.28.0
  
  # Sync dependencies from lock file
  %(prog)s sync --file requirements.lock
  
  # Verify hashes in requirements file
  %(prog)s verify --file requirements.lock
  
  # Poetry operations
  %(prog)s poetry-lock
  %(prog)s poetry-update
  %(prog)s poetry-export
  
  # Security check
  %(prog)s security-check
  
  # Compare two lock files
  %(prog)s compare --file1 old.lock --file2 new.lock
  
  # Generate dependency report
  %(prog)s report
        """
    )
    
    parser.add_argument('--project-root', default='.', help='Project root directory')
    
    subparsers = parser.add_subparsers(dest='command', help='Command to execute')
    
    lock_parser = subparsers.add_parser('lock', help='Generate locked requirements with hashes')
    lock_parser.add_argument('--input', required=True, help='Input requirements file')
    lock_parser.add_argument('--output', required=True, help='Output lock file')
    
    freeze_parser = subparsers.add_parser('freeze', help='Freeze current environment')
    freeze_parser.add_argument('--output', help='Output file (default: requirements.lock)')
    
    subparsers.add_parser('outdated', help='Check for outdated packages')
    
    update_parser = subparsers.add_parser('update', help='Update a package')
    update_parser.add_argument('package', help='Package name')
    update_parser.add_argument('--version', help='Specific version to install')
    
    sync_parser = subparsers.add_parser('sync', help='Sync dependencies from file')
    sync_parser.add_argument('--file', required=True, help='Requirements file to sync from')
    
    verify_parser = subparsers.add_parser('verify', help='Verify hashes in requirements file')
    verify_parser.add_argument('--file', required=True, help='Requirements file to verify')
    
    subparsers.add_parser('poetry-lock', help='Lock Poetry dependencies')
    
    poetry_update_parser = subparsers.add_parser('poetry-update', help='Update Poetry dependencies')
    poetry_update_parser.add_argument('--package', help='Specific package to update')
    
    poetry_export_parser = subparsers.add_parser('poetry-export', help='Export Poetry dependencies')
    poetry_export_parser.add_argument('--output', help='Output file')
    poetry_export_parser.add_argument('--no-hashes', action='store_true', help='Export without hashes')
    
    subparsers.add_parser('security-check', help='Check for security vulnerabilities')
    
    compare_parser = subparsers.add_parser('compare', help='Compare two lock files')
    compare_parser.add_argument('--file1', required=True, help='First file')
    compare_parser.add_argument('--file2', required=True, help='Second file')
    
    report_parser = subparsers.add_parser('report', help='Generate dependency report')
    report_parser.add_argument('--output', help='Output file')
    
    args = parser.parse_args()
    
    if not args.command:
        parser.print_help()
        return
    
    manager = DependencyManager(args.project_root)
    
    if args.command == 'lock':
        manager.generate_requirements_with_hashes(Path(args.input), Path(args.output))
    
    elif args.command == 'freeze':
        output = Path(args.output) if args.output else None
        manager.freeze_dependencies(output)
    
    elif args.command == 'outdated':
        manager.check_outdated_dependencies()
    
    elif args.command == 'update':
        manager.update_dependency(args.package, args.version)
    
    elif args.command == 'sync':
        manager.sync_dependencies(Path(args.file))
    
    elif args.command == 'verify':
        manager.verify_hashes(Path(args.file))
    
    elif args.command == 'poetry-lock':
        manager.poetry_lock()
    
    elif args.command == 'poetry-update':
        manager.poetry_update(args.package)
    
    elif args.command == 'poetry-export':
        output = Path(args.output) if args.output else None
        manager.poetry_export(output, not args.no_hashes)
    
    elif args.command == 'security-check':
        manager.check_security_vulnerabilities()
    
    elif args.command == 'compare':
        manager.compare_lock_files(Path(args.file1), Path(args.file2))
    
    elif args.command == 'report':
        output = Path(args.output) if args.output else None
        manager.generate_dependency_report(output)


if __name__ == "__main__":
    main()